// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: empty / single base items ---
  it.todo("should quote 5 G for an empty item list (processing fee only)");
  it.todo("should quote 105 G for a single plain sword (100 base + 5 fee) for an existing customer");
  it.todo("should quote 65 G for a single plain amulet (60 base + 5 fee)");
  it.todo("should quote 85 G for a single plain staff (80 base + 5 fee)");
  it.todo("should quote 45 G for a single plain potion (40 base + 5 fee)");

  // --- Quote: components (runes/moonstones) ---
  it.todo("should quote 30 G for a single rune (25 base + 5 fee)");
  it.todo("should quote 55 G for 2 runes (50 base + 5 fee)");
  it.todo("should quote 65 G for 3 runes as a block (60 base + 5 fee)");
  it.todo("should quote 105 G for 4 runes (block of 3 + 1 = 60 + 25 + 5 fee)");
  it.todo("should quote 180 G for 7 runes (2 blocks of 3 + 1 single = 60 + 60 + 25 + 5 fee)");
  it.todo("should quote 80 G for 2 runes + 1 moonstone (no block, different types: 50 + 25 + 5 fee)");
  it.todo("should quote 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");

  // --- Quote: per-item surcharges ---
  it.todo("should add 50% surcharge to a cursed item's base premium");
  it.todo("should add 30% surcharge to an item with enchantment level >= 5");
  it.todo("should stack cursed and high-enchantment surcharges on the same item");

  // --- Quote: policy-wide modifiers ---
  it.todo("should add 10% first-insurance surcharge per item for a newcomer customer");
  it.todo("should apply 20% loyalty discount when customer has >= 2 years with MHPCO");
  it.todo("should apply 15% follow-up contract discount on the second and later contracts");

  // --- Quote: rounding and fee ---
  it.todo("should round premium up to whole G in MHPCO's favor (e.g. 197.5 -> 198)");
  it.todo("should add the 5 G processing fee at the end of premium calculation");

  // --- Quote: worked examples from the spec ---
  it.todo("should quote 165 G for newcomer cursed steel sword ench 3 (100 + 50 + 10 + 5 fee)");
  it.todo("should quote 160 G for 3-year customer's 2nd quote cursed sword ench 7 (100 + 50 + 30 - 20 + 10 - 15 + 5 fee)");

  // --- Claim: basic payout ---
  it.todo("should pay out damage minus 100 G deductible per damage event");
  it.todo("should report remainingCap after a claim against the policy");
  it.todo("should cap total payout per policy at 2x insurance sum");
  it.todo("should round payout down to whole G in MHPCO's favor (e.g. 350.5 -> 350)");

  // --- Claim: enchantment and material rules ---
  it.todo("should reimburse 50% of damage (then deductible) for items with enchantment >= 8");
  it.todo("should reimburse damage in full (then deductible) for dragon-material items");
  it.todo("should apply the 50% rule (not full reimbursement) when both dragon material and enchantment >= 8 apply");

  // --- Claim: worked examples from the spec ---
  it.todo("should pay 400 G for dragon sword ench 8 with 1000 G damage (50% wins, then deductible)");
  it.todo("should pay 700 G for dragon sword ench 5 with 800 G damage (full reimbursement minus deductible)");
  it.todo("should pay 400 G for steel sword ench 9 with 1000 G damage (50% rule, then deductible)");

  // --- Claim: cap across multiple claims ---
  it.todo("should pay 1400 G with remainingCap 600 for first 1500 G claim on a sword policy (cap 2000)");
  it.todo("should pay 600 G with remainingCap 0 for a second 1500 G claim that hits the cap");

  // --- Claim: multiple items of same type ---
  it.todo("should treat each damage entry separately (each gets its own deductible) for two damaged swords");

  // --- Errors ---
  it.todo("should exit non-zero and write to stderr for an unknown item type");
  it.todo("should exit non-zero and write to stderr when damage references an unknown item");
  it.todo("should exit non-zero and write to stderr for a negative amount");
  it.todo("should exit non-zero and write to stderr when more damage entries of a type are reported than were insured");
});
